   509→  };
   510→
   511→  if (!frames || frames.length === 0) return defaultResult;
   512→
   513→  const transcription = options.transcription || '';
   514→  const durationSeconds = options.durationSeconds || 60;
   515→  const question = options.question || 'a practice interview question';
   516→  const frameCount = frames.length;
   517→
