   520→    // Select key frames (max 4 to control token costs — 320×240 JPEG each)
   521→    const keyFrames = frames.length > 4 ? selectKeyFrames(frames, 4) : frames;
   522→
   523→    // Upload frames to R2 in parallel (vision APIs need HTTP URLs, not base64)
   524→    console.log(`[video-analysis] Uploading ${keyFrames.length} frames to R2 for vision analysis...`);
   525→    const uploadResults = await Promise.all(
   526→      keyFrames.map((frame, i) => uploadFrameToR2(frame, i))
   527→    );
   528→    const imageUrls = uploadResults.filter(url => url !== null);
   529→
   530→    if (imageUrls.length > 0) {
   531→      console.log(`[video-analysis] ${imageUrls.length}/${keyFrames.length} frames uploaded to R2. Calling vision API...`);
   532→
   533→      const visionPrompt = `You are an expert interview presentation coach. Analyze these ${imageUrls.length} video frames captured during an interview practice recording.
   534→
   535→**Interview Question:** "${question}"
   536→**Response Duration:** ${durationSeconds} seconds
   537→**Transcription excerpt:** "${transcription.substring(0, 500)}"
   538→
   539→Look at the ACTUAL video frames and analyze:
