   678→// Analyze speech transcription for communication quality
   679→function analyzeSpeechPatterns(transcription, durationSeconds) {
   680→  const words = transcription.trim().split(/\s+/).filter(w => w.length > 0);
   681→  const wordCount = words.length;
   682→  const wpm = durationSeconds > 0 ? Math.round((wordCount / durationSeconds) * 60) : 0;
   683→
   684→  // Filler word detection
   685→  const fillerWords = ['um', 'uh', 'like', 'you know', 'so', 'basically', 'actually', 'literally', 'right', 'okay so', 'i mean'];
   686→  const fillerCounts = {};
   687→  let totalFillers = 0;
   688→  const lowerTranscription = transcription.toLowerCase();
   689→
   690→  for (const filler of fillerWords) {
   691→    const regex = new RegExp(`\\b${filler}\\b`, 'gi');
   692→    const matches = lowerTranscription.match(regex);
   693→    if (matches && matches.length > 0) {
   694→      fillerCounts[filler] = matches.length;
   695→      totalFillers += matches.length;
   696→    }
   697→  }
   698→
   699→  const fillerRate = wordCount > 0 ? (totalFillers / wordCount) * 100 : 0;
   700→
   701→  // Pace analysis
   702→  let paceAssessment = 'good';
   703→  let paceFeedback = '';
   704→  if (wpm < 100) {
   705→    paceAssessment = 'too_slow';
   706→    paceFeedback = 'Your speaking pace is quite slow. Try to speak more naturally and with more energy. Aim for 120-150 words per minute.';
   707→  } else if (wpm < 120) {
   708→    paceAssessment = 'slightly_slow';
   709→    paceFeedback = 'Your pace is a bit slow. Try to increase your speaking speed slightly for more engaging delivery.';
   710→  } else if (wpm <= 160) {
   711→    paceAssessment = 'good';
   712→    paceFeedback = 'Your speaking pace is natural and easy to follow. Well done!';
   713→  } else if (wpm <= 180) {
   714→    paceAssessment = 'slightly_fast';
   715→    paceFeedback = 'You\'re speaking a bit quickly. Try to slow down slightly and pause between key points.';
   716→  } else {
   717→    paceAssessment = 'too_fast';
   718→    paceFeedback = 'You\'re speaking too fast — this can signal nervousness. Take deliberate pauses between sentences and breathe.';
   719→  }
   720→
   721→  // Sentence structure analysis
   722→  const sentences = transcription.split(/[.!?]+/).filter(s => s.trim().length > 0);
   723→  const avgSentenceLength = sentences.length > 0 ? Math.round(wordCount / sentences.length) : 0;
   724→
   725→  // Communication score (1-10)
   726→  let communicationScore = 7;
   727→  // Penalize for filler words
   728→  if (fillerRate > 5) communicationScore -= 2;
   729→  else if (fillerRate > 3) communicationScore -= 1;
   730→  // Penalize for bad pace
   731→  if (paceAssessment === 'too_slow' || paceAssessment === 'too_fast') communicationScore -= 1.5;
   732→  else if (paceAssessment === 'slightly_slow' || paceAssessment === 'slightly_fast') communicationScore -= 0.5;
   733→  // Reward for good sentence structure
   734→  if (avgSentenceLength >= 10 && avgSentenceLength <= 25) communicationScore += 0.5;
   735→  // Penalize for very short responses
   736→  if (wordCount < 50) communicationScore -= 2;
   737→  else if (wordCount < 100) communicationScore -= 1;
   738→  // Reward for substantial responses
   739→  if (wordCount >= 150 && wordCount <= 400) communicationScore += 0.5;
   740→
   741→  communicationScore = Math.max(1, Math.min(10, Math.round(communicationScore * 10) / 10));
   742→
   743→  return {
   744→    word_count: wordCount,
   745→    duration_seconds: durationSeconds,
   746→    words_per_minute: wpm,
   747→    filler_words: fillerCounts,
   748→    total_fillers: totalFillers,
   749→    filler_rate: Math.round(fillerRate * 10) / 10,
   750→    pace: {
   751→      assessment: paceAssessment,
   752→      wpm,
   753→      feedback: paceFeedback
   754→    },
   755→    sentence_count: sentences.length,
   756→    avg_sentence_length: avgSentenceLength,
   757→    communication_score: communicationScore,
   758→    tips: generateSpeechTips(fillerRate, wpm, wordCount, totalFillers, fillerCounts)
   759→  };
   760→}
   761→
   762→function generateSpeechTips(fillerRate, wpm, wordCount, totalFillers, fillerCounts) {
   763→  const tips = [];
   764→
   765→  if (fillerRate > 3) {
   766→    const topFillers = Object.entries(fillerCounts)
   767→      .sort((a, b) => b[1] - a[1])
   768→      .slice(0, 3)
   769→      .map(([word, count]) => `"${word}" (${count}x)`);
   770→    tips.push(`Reduce filler words — you used ${totalFillers} fillers: ${topFillers.join(', ')}. Try pausing silently instead.`);
   771→  }
   772→
   773→  if (wpm > 160) {
   774→    tips.push('Slow down your pace. Take a breath between key points to let your message land.');
   775→  } else if (wpm < 110) {
   776→    tips.push('Pick up the pace slightly. A faster tempo projects confidence and engagement.');
   777→  }
   778→
   779→  if (wordCount < 80) {
   780→    tips.push('Your response was quite short. Aim for 1-2 minutes of speaking time to give a comprehensive answer.');
   781→  }
   782→
   783→  if (tips.length === 0) {
   784→    tips.push('Strong verbal delivery! Your pace and clarity are good. Keep practicing to maintain consistency.');
   785→  }
   786→
   787→  return tips;
   788→}
