  1142→// AI interviewer conducts a conversational interview turn
  1143→async function conductInterviewTurn(conversation, baseQuestions, currentQuestionIndex, targetRole, options = {}) {
  1144→  // Send last 12 turns for better context on follow-ups
  1145→  const recentConvo = conversation.slice(-12);
  1146→  const convoText = recentConvo.map(turn => {
  1147→    if (turn.role === 'interviewer') return `INTERVIEWER: ${turn.text}`;
  1148→    return `CANDIDATE: ${turn.text}`;
  1149→  }).join('\n\n');
  1150→
  1151→  const candidateTurnCount = conversation.filter(t => t.role === 'candidate').length;
  1152→  const followUpCount = conversation.filter(t => t.role === 'interviewer' && (t.action === 'follow_up' || t.action === 'challenge')).length;
  1153→  const remainingQuestions = baseQuestions.slice(currentQuestionIndex);
  1154→  const nextPlannedQuestion = remainingQuestions.length > 0
  1155→    ? remainingQuestions[0].question_text
  1156→    : null;
  1157→
  1158→  // Count consecutive follow-ups on the current topic
  1159→  let consecutiveFollowUps = 0;
  1160→  for (let i = conversation.length - 1; i >= 0; i--) {
  1161→    const t = conversation[i];
  1162→    if (t.role === 'interviewer' && (t.action === 'follow_up' || t.action === 'challenge')) {
  1163→      consecutiveFollowUps++;
  1164→    } else if (t.role === 'interviewer' && t.action === 'transition') {
  1165→      break;
  1166→    } else if (t.role === 'candidate') {
  1167→      continue; // skip candidate turns when counting
  1168→    }
  1169→  }
  1170→
  1171→  const prompt = `You are conducting a mock interview for a "${targetRole}" position. You have ${remainingQuestions.length} planned questions remaining.
  1172→
  1173→CONVERSATION SO FAR:
  1174→${convoText}
  1175→
  1176→${nextPlannedQuestion ? `NEXT PLANNED QUESTION (use when ready to move on): "${nextPlannedQuestion}"` : 'All planned questions covered.'}
  1177→
  1178→FOLLOW-UP COUNT on current topic: ${consecutiveFollowUps}
  1179→
  1180→YOUR TASK: Act like a real interviewer. After the candidate answers:
  1181→
  1182→1. **FOLLOW UP** if the answer is:
  1183→   - Vague or surface-level ("I worked on a project" → ask WHAT project, what was the challenge)
  1184→   - Missing specifics (no metrics, no concrete examples, no details about their role)
  1185→   - Interesting but unexplored (they mentioned something worth digging into)
  1186→   - Missing the "so what" (they described what happened but not the impact/result)
  1187→   You can ask MULTIPLE follow-ups on the same topic. Keep probing until you have real depth.
  1188→
  1189→2. **TRANSITION** to the next planned question when:
  1190→   - The candidate gave a thorough, specific answer with concrete examples
  1191→   - You've already asked 2-3 follow-ups and have sufficient depth
  1192→   - The candidate clearly has nothing more to add on this topic
  1193→
  1194→3. **WRAP UP** when: ${candidateTurnCount >= 6 ? 'You feel you have enough data (6+ exchanges completed)' : 'NOT YET — keep interviewing, only ' + candidateTurnCount + ' exchanges so far'}
  1195→
  1196→React to their answer specifically (1-2 sentences — reference something concrete they said, NOT generic filler like "Thank you for that response" or "That's helpful"). Show you actually listened. Example good reactions: "That 40% improvement in pipeline throughput is impressive — how did you measure that?" or "Interesting that you chose to refactor first rather than ship the feature." Example bad reactions: "Thank you for sharing that." or "That's great, thanks."
  1197→
  1198→Return JSON: {"reaction":"1-2 sentences referencing SPECIFIC details from their answer","action":"follow_up|challenge|transition|wrap_up","question":"your next question","score_hint":1-10,"notes":"brief note on answer quality"}`;
  1199→
  1200→  const result = await chat(prompt, {
  1201→    system: `You are Alex, an experienced ${targetRole} interviewer. You conduct interviews like a real person — curious, attentive, and thorough. You don't just read from a script. When a candidate gives a vague answer, you probe deeper. When they mention something interesting, you explore it. You ask follow-up questions naturally, like "Tell me more about that" or "What specifically was your role in that?" or "How did you measure success?" You only move to the next planned question when you're genuinely satisfied with the depth of their answer. Always return valid JSON only.`,
  1202→    maxTokens: 1024,
  1203→    subscriptionId: options.subscriptionId,
  1204→    module: 'mock_interview', feature: 'interview_turn'
  1205→  });
  1206→
  1207→  const parsed = safeParseJSON(result);
  1208→  if (parsed) return parsed;
  1209→  throw new Error('Failed to generate interview turn — could not parse LLM response');
  1210→}
