  1219→
  1220→  // Calculate basic metrics from the text
  1221→  const candidateTurns = conversation.filter(t => t.role === 'candidate');
  1222→  const allCandidateText = candidateTurns.map(t => t.text).join(' ');
  1223→  const wordCount = allCandidateText.split(/\s+/).filter(w => w).length;
