  1354→// ─── TTS: Now with automatic fallback + database caching ─────
  1355→// Fallback chain: Cache → OpenAI TTS → null (browser Web Speech API fallback)
  1356→async function textToSpeech(text, options = {}) {
  1357→  const pool = require('./db');
  1358→  const crypto = require('crypto');
  1359→
  1360→  try {
  1361→    const voice = options.voice || 'nova';
  1362→    const speed = options.speed || 1.0;
  1363→
  1364→    // Truncate text to ~4000 chars (TTS API limit is 4096)
  1365→    const truncatedText = text.length > 4000 ? text.substring(0, 4000) : text;
  1366→
  1367→    // Generate cache key from text + voice
  1368→    const cacheKey = crypto.createHash('sha256').update(`${voice}:${truncatedText}`).digest('hex');
  1369→
  1370→    // Check cache first — serves audio even when daily token limit is exhausted
  1371→    try {
  1372→      const cached = await pool.query(
  1373→        'SELECT audio_data FROM tts_cache WHERE text_hash = $1',
  1374→        [cacheKey]
  1375→      );
  1376→      if (cached.rows.length > 0 && cached.rows[0].audio_data) {
  1377→        const buf = Buffer.from(cached.rows[0].audio_data);
  1378→        console.log(`[tts] Cache HIT: ${truncatedText.length} chars, ${buf.length} bytes (voice: ${voice})`);
  1379→        return buf;
  1380→      }
  1381→    } catch (cacheErr) {
  1382→      // Cache miss or table doesn't exist yet — continue to API
  1383→      console.log(`[tts] Cache check failed (${cacheErr.message}), proceeding to API`);
  1384→    }
  1385→
  1386→    console.log(`[tts] Cache MISS — generating speech: ${truncatedText.length} chars, voice: ${voice}`);
  1387→
  1388→    // Use provider service with automatic fallback
  1389→    const buf = await aiProvider.textToSpeech(truncatedText, {
  1390→      voice,
  1391→      speed,
  1392→      subscriptionId: options.subscriptionId,
  1393→      module: 'mock_interview', feature: 'tts',
  1394→    });
  1395→
  1396→    if (!buf) {
  1397→      console.log('[tts] All providers failed, returning null for browser fallback');
  1398→      return null;
  1399→    }
  1400→
  1401→    console.log(`[tts] Generated ${buf.length} bytes of MP3 audio`);
  1402→
  1403→    // Cache the audio for future use (non-blocking)
  1404→    if (buf.length > 100) {
  1405→      pool.query(
  1406→        `INSERT INTO tts_cache (text_hash, voice, audio_data, text_preview)
  1407→         VALUES ($1, $2, $3, $4)
  1408→         ON CONFLICT (text_hash) DO NOTHING`,
  1409→        [cacheKey, voice, buf, truncatedText.substring(0, 100)]
  1410→      ).then(() => {
  1411→        console.log(`[tts] Cached audio for: "${truncatedText.substring(0, 50)}..."`);
  1412→      }).catch(err => {
  1413→        // Non-fatal — caching failure doesn't break TTS
  1414→        console.warn(`[tts] Cache write failed: ${err.message}`);
  1415→      });
  1416→    }
  1417→
  1418→    return buf;
  1419→  } catch (err) {
  1420→    console.error('[tts] Error:', err.message || err);
  1421→    return null;
  1422→  }
  1423→}
