                            {coaching.communication.tips.map((tip, i) => (
                              <li key={i} className="text-xs text-blue-700">{tip}</li>
                            ))}
                          </ul>
                        </div>
                      )}

                      {coaching.communication.voice_analysis && (
                        <div className="space-y-2 pt-1">
