// Step 2: Run all analyses in parallel with a 25s overall timeout
// BUG FIX (Feb 14, 2026): Vision providers can take 30s+ per attempt × 3 providers = 90s total.
// Safari/iOS kills fetch after ~60s with "Load failed". Wrapping in 25s timeout ensures we always
// return partial results rather than timing out the entire request.
const ANALYSIS_TIMEOUT_MS = 25000;

// FIX (Feb 15, 2026): Pass transcription context to video presentation analysis
// so the text-based LLM can generate personalized coaching from speech patterns
const presentationOptions = {
  ...options,
  transcription: finalTranscription,
  durationSeconds,
  question,
};

const analysisPromises = [
  analyzeInterviewResponse(question, finalTranscription, keyPoints, options),
  generateInterviewCoaching(question, finalTranscription, { score: 5, strengths: [], improvements: [] }, options),
  analyzeVideoPresentation(frames, presentationOptions)
];

// Add voice quality analysis if we have audio
if (audioData) {
  analysisPromises.push(analyzeVoiceQuality(finalTranscription, durationSeconds, options));
}

// Race the parallel analyses against the overall timeout
let settled;
try {
  settled = await Promise.race([
    Promise.allSettled(analysisPromises),
    new Promise((resolve) => setTimeout(() => {
      console.warn(`[video-analysis] Overall analysis timeout after ${ANALYSIS_TIMEOUT_MS}ms — returning partial results`);
      // Return all-rejected so fallbacks kick in for anything not yet done
      resolve(analysisPromises.map(() => ({ status: 'rejected', reason: new Error('Overall analysis timeout') })));
    }, ANALYSIS_TIMEOUT_MS))
  ]);
} catch (err) {
  console.error('[video-analysis] Promise.race unexpected error:', err.message);
  settled = analysisPromises.map(() => ({ status: 'rejected', reason: err }));
}

